import{_ as a,o as l,c as i,a4 as o}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"공유로 가져오기","description":"","frontmatter":{},"headers":[],"relativePath":"11-share-import.md","filePath":"11-share-import.md"}'),r={name:"11-share-import.md"};function t(d,e,c,n,h,s){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="공유로-가져오기" tabindex="-1">공유로 가져오기 <a class="header-anchor" href="#공유로-가져오기" aria-label="Permalink to “공유로 가져오기”">​</a></h1><p><em>공유 가져오기 선택 화면</em></p><p>다른 앱(브라우저, 파일, 사진 등)에서 ebookflowy로 <code>공유</code> 또는 <code>다음으로 열기</code>를 하면 내용을 보관함으로 가져올 수 있습니다. 파일을 일일이 저장한 뒤 추가하지 않아도 됩니다.</p><h2 id="가져오는-방법" tabindex="-1">가져오는 방법 <a class="header-anchor" href="#가져오는-방법" aria-label="Permalink to “가져오는 방법”">​</a></h2><ol><li>다른 앱에서 공유 버튼을 누릅니다.</li><li>공유 대상에서 ebookflowy를 고릅니다.</li><li>항목에 따라 저장 방식이 정해지거나, 형식을 선택하는 화면이 나옵니다.</li></ol><h2 id="항목별-처리" tabindex="-1">항목별 처리 <a class="header-anchor" href="#항목별-처리" aria-label="Permalink to “항목별 처리”">​</a></h2><ul><li>지원 문서(PDF, EPUB 등): 보관함에 추가</li><li>URL·링크 텍스트·일반 텍스트: 보관함 항목으로 처리</li><li>이미지: PDF 또는 CBZ 형식 중 선택해 저장</li><li>여러 이미지: 한 권의 PDF/CBZ로 묶기</li><li><code>.ebslide</code>: 슬라이드 책장의 슬라이드북으로 가져오기</li></ul><h2 id="열기-정책" tabindex="-1">열기 정책 <a class="header-anchor" href="#열기-정책" aria-label="Permalink to “열기 정책”">​</a></h2><p>가져온 항목은 홈·보관함(또는 슬라이드 책장)에 남습니다. 최신 기본 동작에서는 가져온 뒤 리더를 자동으로 열지 않으므로, 원하는 때에 직접 열어 보면 됩니다. 의도치 않게 읽기 흐름이 끊기지 않도록 한 설계입니다.</p><h2 id="내부-복사본으로-안전하게" tabindex="-1">내부 복사본으로 안전하게 <a class="header-anchor" href="#내부-복사본으로-안전하게" aria-label="Permalink to “내부 복사본으로 안전하게”">​</a></h2><p>공유로 가져온 문서는 앱 내부에 관리 복사본으로 저장됩니다. 그래서 다음 상황에서도 계속 열 수 있습니다.</p><ul><li>앱을 재시작한 뒤</li><li>외부 원본이 삭제된 뒤</li><li>외부 폴더 접근 권한이 만료된 뒤</li></ul><p>반대로, 외부 원본을 직접 참조하는 문서(Android SAF/iOS 북마크)는 권한이 만료되면 다시 선택이 필요할 수 있습니다.</p><blockquote><p>가져온 이미지로 새 PDF를 만드는 방법은 <code>PDF 만들기</code>도 함께 참고하세요.</p></blockquote>',14)])])}const m=a(r,[["render",t]]);export{_ as __pageData,m as default};
